/**
 * @fileoverview Slider view — DOM construction, effects, rendering.
 * @module module/Slider/view
 */
import razyui from '../../index.js';
import { CLS, DEFAULTS, MAX_TICKS, PART } from './constants.js';
import { toPercent, formatValue } from './helpers.js';

/**
 * Create a single thumb element with an optional tooltip.
 * @param {string}  id           — 'a' or 'b'
 * @param {boolean} showTooltip
 * @param {boolean} portalTooltip — if true, tooltip is appended to document.body
 * @returns {{ thumb: HTMLElement, tooltip: HTMLElement|null }}
 */
function createThumb(id, showTooltip, portalTooltip) {
    const wrapper = razyui.el('div', { className: 'razy-slider-thumb-wrapper' });
    wrapper.css({
        position: 'absolute',
        left: '0',
        top: '0',
        width: '100%',
        height: '100%',
        pointerEvents: 'none'
    });

    const thumb = razyui.el('div', { className: CLS.THUMB, 'data-thumb': id });
    thumb.css('pointer-events', 'auto');
    PART.THUMB.apply(thumb);
    let tooltip = null;

    if (showTooltip) {
        tooltip = razyui.el('span', { className: CLS.TOOLTIP });
        if (portalTooltip) {
            // Portal: append to body with fixed positioning.
            // CSS vars (--sl-tooltip-*) won't resolve outside .rz-slider,
            // so we set explicit inline styles.
            tooltip.css({
                position: 'fixed',
                zIndex: '99999',
                pointerEvents: 'none',
                bottom: 'auto',
                left: '0',
                top: '0',
                transform: 'translateX(-50%)',
                padding: '2px 8px',
                fontSize: '0.5rem',
                fontWeight: '500',
                fontFamily: 'inherit',
                borderRadius: '4px',
                whiteSpace: 'nowrap',
                background: 'var(--rui-text, #333)',
                color: 'var(--rui-bg, #fff)',
                opacity: '0',
                transition: 'opacity 0.15s ease',
            });
            document.body.appendChild(tooltip[0]);

            // Inject arrow pseudo-element via <style> (can't set ::after inline)
            _ensurePortalArrowStyle();

            // Hover show/hide is handled in wireEffects() where
            // track + stateRef are available for repositioning.
        } else {
            thumb.append(tooltip);
            PART.TOOLTIP.apply(tooltip);
        }
    }

    wrapper.append(thumb);
    return { wrapper, thumb, tooltip };
}

/** Inject a shared <style> for portal tooltip arrows (once). */
let _portalArrowInjected = false;
function _ensurePortalArrowStyle() {
    if (_portalArrowInjected) return;
    _portalArrowInjected = true;
    const style = document.createElement('style');
    style.textContent = `
body > .${CLS.TOOLTIP}::after {
    content: '';
    position: absolute;
    top: 100%;
    left: 50%;
    margin-left: -4px;
    border: 4px solid transparent;
    border-top-color: var(--rui-text, #333);
}`;
    document.head.appendChild(style);
}

/**
 * Build the Slider DOM tree inside the host element.
 *
 * @param {Elements} el       — container element (razyui Elements)
 * @param {object}      config
 * @param {boolean}     isRange
 * @returns {{ track, fill, thumbA, tooltipA, thumbB, tooltipB }}
 */
export function buildSliderDOM(el, config, isRange) {
    const min  = config.min  ?? DEFAULTS.min;
    const max  = config.max  ?? DEFAULTS.max;
    const step = config.step ?? DEFAULTS.step;
    const showTooltip = config.showTooltip !== false;
    const portalTooltip = showTooltip;

    // Root classes
    el.addClass('slider ' + CLS.ROOT);
    PART.ROOT.apply(el);
    if (config.disabled) el.addClass(CLS.DISABLED);
    el.html('');

    // Track + fill
    const track = razyui.el('div', { className: CLS.TRACK });
    PART.TRACK.apply(track);

    const fill = razyui.el('div', { className: CLS.FILL })
                       .css({ width: '100%', 'transform-origin': 'left center' });
    PART.FILL.apply(fill);
    track.append(fill);

    // Ticks
    if (config.showTicks) {
        const count = Math.round((max - min) / step);
        if (count > 0 && count <= MAX_TICKS) {
            const tickBar = razyui.el('div', { className: CLS.TICKS });
            PART.TICKS.apply(tickBar);
            for (let i = 0; i <= count; i++) {
                const tick = razyui.el('span', { className: CLS.TICK });
                PART.TICK.apply(tick);
                tick.css('left', ((i / count) * 100) + '%');
                tickBar.append(tick);
            }
            track.append(tickBar);
        }
    }

    // Thumb A
    const tA = createThumb('a', showTooltip, portalTooltip);
    track.append(tA.wrapper);

    // Thumb B (range mode only)
    let tB = { wrapper: null, thumb: null, tooltip: null };
    if (isRange) {
        tB = createThumb('b', showTooltip, portalTooltip);
        track.append(tB.wrapper);
    }

    el.append(track);

    return {
        track,
        fill,
        wrapperA: tA.wrapper,
        thumbA:   tA.thumb,
        tooltipA: tA.tooltip,
        wrapperB: tB.wrapper,
        thumbB:   tB.thumb,
        tooltipB: tB.tooltip,
    };
}

/**
 * Wire the reactive effect that syncs thumb positions, fill bar,
 * ARIA attributes, and tooltip text to state changes.
 *
 * @param {{ fill, thumbA, tooltipA, thumbB, tooltipB }} refs
 * @param {object}   stateRef
 * @param {object}   config
 * @param {boolean}  isRange
 * @param {function} effectFn — the effect registrar (stateSet.effect)
 */
export function wireEffects(refs, stateRef, config, isRange, effectFn) {
    const min = config.min ?? DEFAULTS.min;
    const max = config.max ?? DEFAULTS.max;
    const portalTooltip = true;
    const { track, fill, wrapperA, thumbA, tooltipA, wrapperB, thumbB, tooltipB } = refs;

    /** Position a portaled (fixed) tooltip above its thumb element. */
    function positionPortalTooltip(tooltip, thumb, pct) {
        if (!tooltip?.[0] || !thumb?.[0] || !track?.[0]) return;
        const trackRect = track[0].getBoundingClientRect();
        const tipEl = tooltip[0];
        const tipH = tipEl.offsetHeight || 0;
        // Use offsetHeight (unaffected by CSS transform scale) so the
        // tooltip stays stable regardless of :active scale(1.15).
        const thumbH = thumb[0].offsetHeight;
        const trackCenterY = trackRect.top + trackRect.height / 2;
        const left = trackRect.left + (pct / 100) * trackRect.width;
        const top  = Math.round(trackCenterY - thumbH / 2 - tipH - 6);
        tooltip.css({ left: left + 'px', top: top + 'px', transform: 'translateX(-50%)' });
    }

    // Hover show/hide for portal tooltips — reposition before showing.
    // Skip during drag (is-dragging on root) to avoid flicker from rapid
    // mouseenter/mouseleave events as the thumb moves under the cursor.
    if (portalTooltip) {
        const isDragging = () => thumbA[0]?.closest('.' + CLS.ROOT)?.classList.contains(CLS.DRAGGING);
        const hoverEnterA = () => {
            if (isDragging()) return;
            positionPortalTooltip(tooltipA, thumbA, toPercent(stateRef.a, min, max));
            tooltipA?.css('opacity', '1');
        };
        const hoverLeaveA = () => {
            if (isDragging()) return;
            tooltipA?.css('opacity', '0');
        };
        if (thumbA?.[0]) {
            thumbA[0].addEventListener('mouseenter', hoverEnterA);
            thumbA[0].addEventListener('mouseleave', hoverLeaveA);
        }
        if (isRange && thumbB?.[0]) {
            const hoverEnterB = () => {
                if (isDragging()) return;
                positionPortalTooltip(tooltipB, thumbB, toPercent(stateRef.b, min, max));
                tooltipB?.css('opacity', '1');
            };
            const hoverLeaveB = () => {
                if (isDragging()) return;
                tooltipB?.css('opacity', '0');
            };
            thumbB[0].addEventListener('mouseenter', hoverEnterB);
            thumbB[0].addEventListener('mouseleave', hoverLeaveB);
        }
    }

    effectFn(() => {
        const valA = stateRef.a;
        const valB = stateRef.b;
        const pctA = toPercent(valA, min, max);

        // Position thumb A
        wrapperA.css('transform', `translateX(${pctA}%)`);
        thumbA.attr('aria-valuenow', valA);
        if (tooltipA) {
            tooltipA.text(formatValue(valA, config.formatValue));
            if (portalTooltip) positionPortalTooltip(tooltipA, thumbA, pctA);
        }

        if (isRange) {
            const pctB = toPercent(valB, min, max);
            wrapperB.css('transform', `translateX(${pctB}%)`);
            thumbB.attr('aria-valuenow', valB);
            if (tooltipB) {
                tooltipB.text(formatValue(valB, config.formatValue));
                if (portalTooltip) positionPortalTooltip(tooltipB, thumbB, pctB);
            }

            // Fill between thumbs
            const lo = Math.min(pctA, pctB);
            const hi = Math.max(pctA, pctB);
            fill.css('transform', `translateX(${lo}%) scaleX(${(hi - lo) / 100})`);
        } else {
            // Fill from 0 to thumb
            fill.css('transform', `scaleX(${pctA / 100})`);
        }
    });
}

/**
 * Set standard ARIA attributes on a thumb element.
 * @param {HTMLElement} thumb
 * @param {number}      min
 * @param {number}      max
 */
export function setAriaAttrs(thumb, min, max) {
    thumb.attr('role', 'slider');
    thumb.attr('aria-valuemin', min);
    thumb.attr('aria-valuemax', max);
    thumb.attr('tabindex', '0');
}

/**
 * Cleanup — remove slider classes and inner DOM.
 * Also remove any portaled tooltips from document.body.
 * @param {Elements} el — razyui Elements
 * @param {Object} [refs] — optional refs with tooltipA/tooltipB to clean up portals
 */
export function destroyDOM(el, refs) {
    el.removeClass('slider', CLS.ROOT, CLS.DISABLED, CLS.DRAGGING);
    el.html('');
    // Remove portaled tooltips from body
    if (refs?.tooltipA?.[0]?.parentNode === document.body) refs.tooltipA[0].remove();
    if (refs?.tooltipB?.[0]?.parentNode === document.body) refs.tooltipB[0].remove();
}
