/**
 * @fileoverview Slider helpers — pure utility functions.
 * @module module/Slider/helpers
 */
import razyui from '../../index.js';

/**
 * Convert a value to a percentage within [min, max].
 * @param {number} value
 * @param {number} min
 * @param {number} max
 * @returns {number} percentage (0–100)
 */
export function toPercent(value, min, max) {
    if (max === min) return 0;
    return ((value - min) / (max - min)) * 100;
}

/**
 * Format a slider value for display.
 * @param {number}   value
 * @param {function} [formatter] — optional custom formatter
 * @returns {string}
 */
export function formatValue(value, formatter) {
    if (typeof formatter === 'function') return formatter(value);
    return String(value);
}

/**
 * Snap a value to the nearest step, clamped to [min, max].
 * @param {number} value
 * @param {number} min
 * @param {number} max
 * @param {number} step
 * @returns {number}
 */
export function snapValue(value, min, max, step) {
    const snapped = Math.round((value - min) / step) * step + min;
    // Fix floating-point precision
    const decimals = (String(step).split('.')[1] || '').length;
    const fixed = parseFloat(snapped.toFixed(decimals));
    return razyui.clamp(fixed, min, max);
}

/**
 * Compute a slider value from a pointer event relative to a track element.
 * @param {PointerEvent} e
 * @param {HTMLElement}   trackEl
 * @param {number}        min
 * @param {number}        max
 * @param {function}      snapFn — (value) => snapped value
 * @returns {number}
 */
export function valueFromPointer(e, trackEl, min, max, snapFn) {
    const raw = trackEl?.[0] ?? trackEl;
    const rect = raw.getBoundingClientRect();
    const ratio = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
    return snapFn(min + ratio * (max - min));
}
