/**
 * @fileoverview Slider constants — CSS class names, selectors, and defaults.
 * @module module/Slider/constants
 */
import { defineParts } from '../shared/definePart.js';


// ── CSS class names ──
export const CLS = Object.freeze({
    ROOT:       'rz-slider',
    TRACK:      'rz-slider-track',
    FILL:       'rz-slider-fill',
    TICKS:      'rz-slider-ticks',
    TICK:       'rz-slider-tick',
    THUMB:      'rz-slider-thumb',
    TOOLTIP:    'rz-slider-tooltip',
    disabled:   'is-disabled',
    DRAGGING:   'is-dragging',
    INVALID:    'is-invalid',
});

// ── Default configuration values ──
export const DEFAULTS = Object.freeze({
    min:          0,
    max:          100,
    step:         1,
    showTooltip: true,
    showTicks:   false,
    disabled:     false,
});

// ── Magic numbers ──
/** Maximum number of ticks before they are suppressed. */
export const MAX_TICKS = 30;

/** Semantic part names for pre-render styling overrides. */
export const PART = defineParts('Slider', {
    ROOT        : { class: 'rz-slider', aliases: ['slider', 'root', 'container'] },
    TRACK       : { class: 'rz-slider-track', aliases: ['track'] },
    FILL        : { class: 'rz-slider-fill' },
    THUMB       : { class: 'rz-slider-thumb' },
    TOOLTIP     : { class: 'rz-slider-tooltip' },
    TICKS       : { class: 'rz-slider-ticks' },
    TICK        : { class: 'rz-slider-tick' },
});

PART.ROOT.jit     = 'relative w-full [padding:var(--sl-padding-y)_var(--sl-padding-x)] [overflow-x:clip] select-none [touch-action:none] {is-disabled}:[opacity:0.45] {is-disabled}:pointer-events-none';
PART.TRACK.jit    = 'relative w-full h-[var(--sl-track-height)] bg-[var(--sl-bg-inset)] rounded-[var(--sl-track-radius)] cursor-pointer';
PART.FILL.jit     = 'absolute [top:0] h-full bg-[var(--sl-accent)] rounded-[var(--sl-track-radius)] pointer-events-none [transition:width_var(--rui-transition-fast)_var(--rui-transition-easing),left_var(--rui-transition-fast)_var(--rui-transition-easing)] ^{is-dragging}:[transition:none] ^{is-dragging}:[will-change:transform]';
PART.THUMB.jit    = 'absolute [top:50%] [left:0] w-[var(--sl-thumb-size)] h-[var(--sl-thumb-size)] bg-[var(--sl-bg)] [border:var(--sl-thumb-border-width)_solid_var(--sl-accent)] rounded-[50%] [cursor:grab] [z-index:2] [outline:none] [transform:translate(-50%,-50%)] [transition:box-shadow_var(--rui-transition-normal)_var(--rui-transition-easing),transform_var(--rui-transition-fast)_var(--rui-transition-easing),left_0.05s_var(--rui-transition-easing)] hover:[box-shadow:0_0_0_4px_var(--sl-accent-subtle)] focus-visible:[box-shadow:0_0_0_4px_var(--sl-accent-subtle)] active:[transform:translate(-50%,-50%)_scale(1.15)] ^{is-dragging}:[transition:box-shadow_var(--rui-transition-normal)_var(--rui-transition-easing),transform_var(--rui-transition-fast)_var(--rui-transition-easing)] ^{is-dragging}:[will-change:transform] ^{is-dragging}:[cursor:grabbing] [&_.rz-slider-tooltip]:hover:[opacity:1] [&_.rz-slider-tooltip]:hover:[transform:translateX(-50%)_translateY(-50%)_scale(1)] [&_.rz-slider-tooltip]:focus-visible:[opacity:1] [&_.rz-slider-tooltip]:focus-visible:[transform:translateX(-50%)_translateY(-50%)_scale(1)]';
PART.TOOLTIP.jit  = 'absolute [top:calc(var(--sl-thumb-size)*-1)] [left:50%] [transform:translateX(-50%)_translateY(-50%)_scale(0.8)] bg-[var(--sl-tooltip-bg)] fg-[var(--sl-tooltip-text)] text-[var(--sl-tooltip-font-size)] fw-500 [font-family:inherit] [padding:var(--sl-tooltip-padding-y)_var(--sl-tooltip-padding-x)] rounded-[var(--sl-tooltip-radius)] text-nowrap pointer-events-none [opacity:0] after:absolute after:[top:100%] after:[left:50%] after:[margin-left:-4px] after:[border:4px_solid_transparent] after:[border-top-color:var(--sl-tooltip-bg)] ^{is-dragging}:[opacity:1] ^{is-dragging}:[transform:translateX(-50%)_translateY(-50%)_scale(1)]';
PART.TICKS.jit    = 'absolute [top:0] [left:0] w-full h-full pointer-events-none';
PART.TICK.jit     = 'absolute [top:-3px] w-[var(--sl-tick-width)] h-[var(--sl-tick-height)] [margin-left:-1px] bg-[var(--sl-border-strong)] rounded-[1px]';