/**
 * @fileoverview Slider state — reactive state creation.
 * @module module/Slider/state
 */
import razyui from '../../index.js';
import { DEFAULTS } from './constants.js';

/**
 * Create the reactive state for the slider.
 *
 * @param {object}  config   — slider configuration
 * @param {boolean} isRange  — true for dual-thumb mode
 * @returns {{ stateRef: object, setState: function, effect: function }}
 */
export function createSliderState(config, isRange) {
    const min = config.min ?? DEFAULTS.min;
    const max = config.max ?? DEFAULTS.max;

    let initA, initB;

    if (isRange) {
        initA = razyui.clamp(config.range[0] ?? min, min, max);
        initB = razyui.clamp(config.range[1] ?? max, min, max);
        if (initA > initB) [initA, initB] = [initB, initA];
    } else {
        initA = razyui.clamp(config.value ?? min, min, max);
        initB = max;
    }

    const disabled = !!config.disabled;
    const stateSet = razyui.state({ a: initA, b: initB, disabled });
    return {
        stateRef: stateSet[0],
        setState: stateSet[1],
        effect:   stateSet.effect.bind(stateSet),
    };
}
